"use client"

import { useState } from "react"
import { User, UserTick } from "iconsax-react"

type Range = "day" | "week" | "month" | "year"

interface DataItem {
    guest: number
    online: number
}

interface AnalyticsProps {
    data: Record<Range, DataItem>
}

export default function Analytics({ data }: AnalyticsProps) {

    const [range, setRange] = useState<Range>("day")
    const current = data[range]

    const tabs = [
        { key: "day", label: "Ngày" },
        { key: "week", label: "Tuần" },
        { key: "month", label: "Tháng" },
        { key: "year", label: "Năm" }
    ]

    return (
        <div className="
            mt-10 p-5 md:p-6 rounded-2xl
            border border-[#e6e6e6] dark:border-[#222222]
            bg-white dark:bg-[#171717]
        ">

            {/* Header */}
            <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-3 mb-6">

                <h3 className="text-base md:text-lg font-semibold">
                    📊 Thống kê truy cập
                </h3>

                {/* Tabs */}
                <div className="
                    flex p-1 rounded-xl
                    bg-gray-100 dark:bg-[#222]
                    w-fit
                ">
                    {tabs.map((item) => (
                        <button
                            key={item.key}
                            onClick={() => setRange(item.key as Range)}
                            className={`
                                px-3 py-1.5 text-xs md:text-sm rounded-lg transition
                                ${range === item.key
                                    ? "bg-white dark:bg-black shadow text-black dark:text-white"
                                    : "text-gray-500"
                                }
                            `}
                        >
                            {item.label}
                        </button>
                    ))}
                </div>

            </div>

            {/* Stats */}
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">

                {/* Guest */}
                <div className="
                    group p-5 rounded-2xl
                    bg-gradient-to-br from-gray-50 to-white
                    dark:from-[#1f1f1f] dark:to-[#171717]
                    border border-[#e6e6e6] dark:border-[#222]
                    flex items-center justify-between
                    hover:shadow-md hover:-translate-y-1
                    transition
                ">

                    <div>
                        <p className="text-sm text-gray-500 mb-1">Khách</p>
                        <h4 className="text-xl md:text-2xl font-bold">
                            {current.guest.toLocaleString()}
                        </h4>
                    </div>

                    <div className="
                        w-12 h-12 flex items-center justify-center
                        rounded-xl
                        bg-black text-white
                        dark:bg-white dark:text-black
                        group-hover:scale-110 transition
                    ">
                        <User size={22} variant="Bold" />
                    </div>

                </div>

                {/* Online */}
                <div className="
                    group p-5 rounded-2xl
                    bg-gradient-to-br from-green-50 to-white
                    dark:from-[#1f1f1f] dark:to-[#171717]
                    border border-[#e6e6e6] dark:border-[#222]
                    flex items-center justify-between
                    hover:shadow-md hover:-translate-y-1
                    transition
                ">

                    <div>
                        <p className="text-sm text-gray-500 mb-1">Online</p>
                        <h4 className="text-xl md:text-2xl font-bold">
                            {current.online.toLocaleString()}
                        </h4>
                    </div>

                    <div className="
                        w-12 h-12 flex items-center justify-center
                        rounded-xl
                        bg-green-500 text-white
                        group-hover:scale-110 transition
                    ">
                        <UserTick size={22} variant="Bold" />
                    </div>

                </div>

            </div>

        </div>
    )
}